// // This module resets the data output to 0x55 on every negative edge of the clock
module data_storage (
    input clk,
    input reset,
    input [7:0] data_in,
    output reg [7:0] data_out
);

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            data_out <= 8'hAA;
        end else begin
            data_out <= data_in;
        end
    end
endmodule
